import React, { useState, useEffect } from 'react';
import ReactQuill from 'react-quill';
import 'react-quill/dist/quill.snow.css';
import axios from 'axios';
import { Save, Eye, Upload, X, FileText, Image, Video, Music } from 'lucide-react';

const EmailEditor = () => {
  const [activeTab, setActiveTab] = useState('welcome');
  const [emailContent, setEmailContent] = useState('');
  const [subject, setSubject] = useState('');
  const [campaignSubject, setCampaignSubject] = useState('');
  const [campaignContent, setCampaignContent] = useState('');
  const [waWelcomeMessage, setWaWelcomeMessage] = useState('');
  const [waCampaignMessage, setWaCampaignMessage] = useState('');
  const [waConfig, setWaConfig] = useState({ enabled: false, base_url: '', api_key: '', instance: '' });
  const [previewMode, setPreviewMode] = useState(false);
  const [loading, setLoading] = useState(false);
  const [attachments, setAttachments] = useState([]);
  const [clients, setClients] = useState([]);
  const [clientTags, setClientTags] = useState([]);
  const [sendMode, setSendMode] = useState('all');
  const [selectedEmails, setSelectedEmails] = useState({});
  const [selectedTag, setSelectedTag] = useState('atraso');
  const [sending, setSending] = useState(false);
  const [clientSearch, setClientSearch] = useState('');
  const [tagEdit, setTagEdit] = useState({});
  const [config, setConfig] = useState({
    smtp_host: '',
    smtp_port: 587,
    smtp_user: '',
    smtp_password: '',
    from_email: '',
    from_name: ''
  });

  // Funções auxiliares para anexos
  const handleFileUpload = async (e) => {
    const files = Array.from(e.target.files);
    for (const file of files) {
      try {
        const formData = new FormData();
        formData.append('file', file);
        const response = await axios.post('/api/admin/email-template/attachment', formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        setAttachments(prev => [...prev, response.data]);
      } catch (error) {
        alert('Erro ao fazer upload do arquivo: ' + (error.response?.data?.detail || 'Erro interno'));
      }
    }
